// Extract cart payload and shop domain from the Shopify webhook
const body   = $input.first().json.body ?? $input.first().json;
const headers = $input.first().json.headers ?? {};

// Shopify sends the shop domain in the X-Shopify-Shop-Domain header
const shopDomain = headers['x-shopify-shop-domain'] ?? headers['X-Shopify-Shop-Domain'] ?? '';

if (!shopDomain) throw new Error('Missing X-Shopify-Shop-Domain header');
if (!body.id)    throw new Error('Missing cart id in payload');

// Normalise line_items to a clean array
const lineItems = (body.line_items ?? []).map(item => ({
  variant_id:   item.variant_id,
  product_id:   item.product_id,
  title:        item.title,
  quantity:     item.quantity,
  price:        item.price,
  sku:          item.sku ?? null
}));

return [{
  json: {
    shop_domain:          shopDomain,
    external_id:          String(body.id),
    token:                body.token ?? null,
    email:                body.email ?? null,
    customer_external_id: body.customer?.id ? String(body.customer.id) : null,
    total_price:          parseFloat(body.total_price ?? '0'),
    line_items:           lineItems,
    checkout_url:         body.abandoned_checkout_url ?? null,
    external_created_at:  body.created_at ?? null,
    external_updated_at:  body.updated_at ?? null
  }
}];

const cart   = $('Extract Cart Data').first().json;
const brands = $input.first().json;

if (!Array.isArray(brands) || brands.length === 0) {
  throw new Error(`No brand found for shop domain: ${cart.shop_domain}`);
}

return [{
  json: {
    ...cart,
    brand_id: brands[0].id
  }
}];
